1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote - base premiums and processing fee
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("quote for a single plain sword (steel, enchantment 0, not cursed, new customer with no previous contracts) → 100 + 10 (first insurance) + 5 (fee) = 115 G");
14	  it.todo("quote for a single plain amulet → 60 + 6 + 5 = 71 G");
15	  it.todo("quote for a single plain staff → 80 + 8 + 5 = 93 G");
16	  it.todo("quote for a single plain potion → 40 + 4 + 5 = 49 G");
17	
18	  // Components and blocks
19	  it.todo("quote for 1 rune → 25 + 3 (first insurance, rounded up) + 5 = 33 G");
20	  it.todo("quote for 2 runes → 50 + 5 + 5 = 60 G");
21	  it.todo("quote for 3 runes (block) → 60 + 6 + 5 = 71 G");
22	  it.todo("quote for 4 runes (no block) → 100 + 10 + 5 = 115 G");
23	  it.todo("quote for 7 runes → 175 + 18 (rounded up) + 5 = 198 G");
24	  it.todo("quote for 2 runes + 1 moonstone (no block, different types) → 75 + 8 + 5 = 88 G");
25	  it.todo("quote for 3 runes + 3 moonstones (two separate blocks) → 120 + 12 + 5 = 137 G");
26	
27	  // Premium modifiers - item-specific
28	  it.todo("quote for cursed sword adds 50% surcharge on item base premium");
29	  it.todo("quote for sword with enchantment 5 adds 30% high-enchantment surcharge");
30	  it.todo("quote for sword with enchantment 4 has no high-enchantment surcharge");
31	  it.todo("quote for cursed sword with enchantment 5 applies both surcharges");
32	
33	  // Premium modifiers - policy-wide
34	  it.todo("quote for customer with 2 years gets 20% loyalty discount");
35	  it.todo("quote for customer's second contract gets 15% follow-up discount (no first insurance on customer level — first insurance still applies per-item)");
36	
37	  // Multi-item policy
38	  it.todo("quote for cursed sword + plain amulet (newcomer) → 100 + 60 + 50 (curse on sword only) + 16 (first insurance 10%) + 5 = 231 G");
39	
40	  // Rounding
41	  it.todo("premium that yields 197.5 G rounds up to 198 G");
42	
43	  // Integration
44	  it.todo("newcomer with cursed sword → 165 G");
45	  it.todo("long-standing customer's second contract with cursed enchanted sword → 160 G");
46	
47	  // Claim - basic
48	  it.todo("claim with no special clauses: regular sword (steel, ench 3), damage 500 → payout 400");
49	  it.todo("claim for rune (no enchantment, no material), damage 200 → payout 100");
50	  it.todo("claim for sword with enchantment 8 (dragon material), damage 1000 → payout 400 (50% rule, then deductible)");
51	  it.todo("claim for dragon-material sword, enchantment 5, damage 800 → payout 700");
52	  it.todo("claim for steel sword, enchantment 9, damage 1000 → payout 400");
53	  it.todo("claim for dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
54	
55	  // Multiple damages per claim
56	  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 (deductible per item)");
57	
58	  // Cap
59	  it.todo("policy on a sword (cap 2000), two successive 1500-damage claims: first payout 1400, remainingCap 600; second payout 600, remainingCap 0");
60	
61	  // Multiple same-type items
62	  it.todo("policy with two swords; damages for both swords each get their own deductible");
63	  it.todo("claim with more damages of a type than insured items → CLI rejects (error)");
64	
65	  // Payout rounding
66	  it.todo("payout that yields 350.5 G rounds down to 350 G");
67	
68	  // Edge cases / errors
69	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
70	  it.todo("claim referencing damage for item not in policy → CLI exits non-zero");
71	  it.todo("claim with negative damage amount → CLI exits non-zero");
72	});
